import React, { useState, useRef, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import emailjs from '@emailjs/browser';
import ReCAPTCHA from 'react-google-recaptcha';
import Header from '../components/Header';
import Footer from '../components/Footer';
import { useAuth } from '../context/AuthContext';
import API from '../api/axios';
import './Account.css';

/* ── EmailJS config ── */
const EJ_SERVICE  = 'service_3kvw346';
const EJ_TEMPLATE = 'template_nfmoesj';
const EJ_PUBLIC   = 'tbFoPOuJY9xQ6-3U5';

const RECAPTCHA_KEY = process.env.REACT_APP_RECAPTCHA_KEY || '6LdvUogsAAAAAKrOeiwe4FclibOubnh_u2ngbVxJ';

/* ── Generate a 6-digit PIN ── */
const generatePin = () => String(Math.floor(100000 + Math.random() * 900000));

/* ── Send PIN via EmailJS ── */
const sendPinEmail = (toEmail, toName, pin) =>
  emailjs.send(
    EJ_SERVICE,
    EJ_TEMPLATE,
    {
      to_email:   toEmail,
      to_name:    toName || toEmail,
      pin_code:   pin,
      expiry_min: '10',
      brand_name: 'Dream In Lace',
    },
    EJ_PUBLIC
  );

/* ── Reusable 6-box PIN input ── */
function PinInput({ value, onChange, hasError }) {
  const digits = (value || '').padEnd(6, '').split('').slice(0, 6);
  const refs   = useRef([]);

  const handleChange = (i, val) => {
    if (!/^\d?$/.test(val)) return;
    const next = [...digits];
    next[i] = val;
    onChange(next.join('').trimEnd());
    if (val && i < 5) refs.current[i + 1]?.focus();
  };

  const handleKeyDown = (i, e) => {
    if (e.key === 'Backspace' && !digits[i] && i > 0) refs.current[i - 1]?.focus();
    if (e.key === 'ArrowLeft'  && i > 0) refs.current[i - 1]?.focus();
    if (e.key === 'ArrowRight' && i < 5) refs.current[i + 1]?.focus();
  };

  const handlePaste = (e) => {
    e.preventDefault();
    const text = e.clipboardData.getData('text').replace(/\D/g, '').slice(0, 6);
    if (!text) return;
    const next = [...digits];
    text.split('').forEach((ch, i) => { if (i < 6) next[i] = ch; });
    onChange(next.join('').trimEnd());
    refs.current[Math.min(text.length, 5)]?.focus();
  };

  return (
    <div className="pin-inputs" onPaste={handlePaste}>
      {[0,1,2,3,4,5].map(i => (
        <input
          key={i}
          ref={el => refs.current[i] = el}
          className={`pin-input${digits[i] ? ' filled' : ''}${hasError ? ' pin-input--error' : ''}`}
          type="text"
          inputMode="numeric"
          maxLength={1}
          value={digits[i] || ''}
          onChange={e => handleChange(i, e.target.value)}
          onKeyDown={e => handleKeyDown(i, e)}
          autoFocus={i === 0}
        />
      ))}
    </div>
  );
}

export default function Account() {
  const { login, register } = useAuth();
  const navigate = useNavigate();

  const [mode, setMode]       = useState('login');
  const [step, setStep]       = useState(1);
  const [captcha, setCaptcha] = useState(null);
  const [loading, setLoading] = useState(false);
  const [msg, setMsg]         = useState({ text: '', type: '' });
  const [countdown, setCountdown] = useState(0);

  /* Stored PINs — kept in state, never exposed in the DOM */
  const [regPinStored,    setRegPinStored]    = useState('');
  const [forgotPinStored, setForgotPinStored] = useState('');

  const [loginForm, setLoginForm] = useState({ email: '', password: '' });
  const [regForm,   setRegForm]   = useState({ firstName: '', lastName: '', email: '', pin: '', password: '' });
  const [forgotEmail, setForgotEmail] = useState('');
  const [forgotPin,   setForgotPin]   = useState('');
  const [newPassword, setNewPassword] = useState('');

  const setError   = t => setMsg({ text: t, type: 'error' });
  const setSuccess = t => setMsg({ text: t, type: 'success' });
  const clearMsg   = () => setMsg({ text: '', type: '' });
  const switchMode = m => { setMode(m); setStep(1); clearMsg(); };

  useEffect(() => {
    if (countdown <= 0) return;
    const t = setTimeout(() => setCountdown(c => c - 1), 1000);
    return () => clearTimeout(t);
  }, [countdown]);

  /* ── LOGIN ── */
  const handleLogin = async (e) => {
    e.preventDefault(); clearMsg();
    if (!captcha) { setError('Please complete the CAPTCHA.'); return; }
    setLoading(true);
    try {
      await login(loginForm.email, loginForm.password);
      navigate('/profile');
    } catch (err) {
      setError(err.response?.data?.error || 'Invalid email or password.');
    } finally { setLoading(false); }
  };

  /* ── REGISTER: send PIN ── */
  const handleSendPin = async (e) => {
    e.preventDefault(); clearMsg();
    if (!regForm.firstName || !regForm.lastName || !regForm.email) {
      setError('Please fill in all fields.'); return;
    }
    setLoading(true);
    try {
      const pin = generatePin();
      await sendPinEmail(regForm.email, regForm.firstName, pin);
      setRegPinStored(pin);
      setRegForm(f => ({ ...f, pin: '' }));
      setSuccess('Verification PIN sent to your email.');
      setCountdown(60);
      setStep(2);
    } catch {
      setError('Failed to send PIN. Please check your email and try again.');
    } finally { setLoading(false); }
  };

  const handleResendPin = async () => {
    setLoading(true); clearMsg();
    try {
      const pin = generatePin();
      await sendPinEmail(regForm.email, regForm.firstName, pin);
      setRegPinStored(pin);
      setRegForm(f => ({ ...f, pin: '' }));
      setSuccess('New PIN sent to your email.');
      setCountdown(60);
    } catch {
      setError('Could not resend PIN. Please try again.');
    } finally { setLoading(false); }
  };

  /* ── REGISTER: verify PIN (client-side check) ── */
  const handleVerifyPin = async (e) => {
    e.preventDefault(); clearMsg();
    if (regForm.pin.length < 6) { setError('Please enter the full 6-digit PIN.'); return; }
    if (regForm.pin !== regPinStored) {
      setError('Incorrect PIN. Please try again.');
      setRegForm(f => ({ ...f, pin: '' }));
      return;
    }
    setSuccess('Email verified. Now set your password.');
    setStep(3);
  };

  /* ── REGISTER: create account ── */
  const handleCreateAccount = async (e) => {
    e.preventDefault(); clearMsg();
    if (!regForm.password || regForm.password.length < 8) {
      setError('Password must be at least 8 characters.'); return;
    }
    setLoading(true);
    try {
      await register({
        first_name: regForm.firstName,
        last_name:  regForm.lastName,
        email:      regForm.email,
        password:   regForm.password,
        pin:        regForm.pin,
      });
      navigate('/profile');
    } catch (err) {
      setError(err.response?.data?.error || 'Failed to create account.');
    } finally { setLoading(false); }
  };

  /* ── FORGOT: send recovery PIN ── */
  const handleForgotPin = async (e) => {
    e.preventDefault(); clearMsg();
    if (!forgotEmail) { setError('Please enter your email.'); return; }
    setLoading(true);
    try {
      const pin = generatePin();
      await sendPinEmail(forgotEmail, '', pin);
      setForgotPinStored(pin);
      setForgotPin('');
      setSuccess('Recovery PIN sent to your email.');
      setCountdown(60);
      setStep(2);
    } catch {
      setError('Failed to send PIN. Please check your email and try again.');
    } finally { setLoading(false); }
  };

  const handleResendForgotPin = async () => {
    setLoading(true); clearMsg();
    try {
      const pin = generatePin();
      await sendPinEmail(forgotEmail, '', pin);
      setForgotPinStored(pin);
      setForgotPin('');
      setSuccess('New PIN sent.');
      setCountdown(60);
    } catch {
      setError('Could not resend PIN.');
    } finally { setLoading(false); }
  };

  /* ── FORGOT: reset password ── */
  const handleResetPassword = async (e) => {
    e.preventDefault(); clearMsg();
    if (forgotPin.length < 6) { setError('Please enter the full 6-digit PIN.'); return; }
    if (newPassword.length < 8) { setError('Password must be at least 8 characters.'); return; }
    if (forgotPin !== forgotPinStored) {
      setError('Incorrect PIN. Please try again.');
      setForgotPin('');
      return;
    }
    setLoading(true);
    try {
      await API.post('/users/reset-password/', {
        email: forgotEmail, pin: forgotPin, new_password: newPassword,
      });
      setSuccess('Password reset! You can now log in.');
      setTimeout(() => switchMode('login'), 1500);
    } catch (err) {
      setError(err.response?.data?.error || 'Failed to reset password.');
    } finally { setLoading(false); }
  };

  const stepLabel = () => {
    if (mode === 'login')  return 'Welcome back';
    if (mode === 'forgot') return step === 1 ? 'Forgot password' : 'Reset password';
    return step === 1 ? 'Create account' : step === 2 ? 'Verify email' : 'Set password';
  };

  const pinHasError = msg.type === 'error' && step === 2;

  return (
    <>
      <Header />
      <div className="account-page">
        <div className="account-shell">
          <Link to="/" className="account-brand">
            <span className="account-brand__name">Dream In Lace</span>
            <span className="account-brand__sub">Lingerie &amp; Swimwear</span>
          </Link>

          <h1 className="account-heading">{stepLabel()}</h1>

          {/* ── LOGIN ── */}
          {mode === 'login' && (
            <form className="account-form" onSubmit={handleLogin} noValidate>
              <div className="field">
                <label className="field__label">Email</label>
                <input className="field__input" type="email" placeholder="you@example.com"
                  value={loginForm.email} onChange={e => setLoginForm({ ...loginForm, email: e.target.value })} required />
              </div>
              <div className="field">
                <label className="field__label">Password</label>
                <input className="field__input" type="password" placeholder="••••••••"
                  value={loginForm.password} onChange={e => setLoginForm({ ...loginForm, password: e.target.value })} required />
              </div>
              <ReCAPTCHA sitekey={RECAPTCHA_KEY} onChange={setCaptcha} />
              <button className="btn-primary account-submit" type="submit" disabled={loading || !captcha}>
                {loading ? 'Logging in…' : 'Log In'}
              </button>
              {msg.text && <p className={msg.type === 'success' ? 'api-success' : 'api-error'}>{msg.text}</p>}
              <div className="account-links">
                <button type="button" className="account-text-btn" onClick={() => switchMode('forgot')}>Forgot password?</button>
                <button type="button" className="account-text-btn" onClick={() => switchMode('signup')}>Create account →</button>
              </div>
            </form>
          )}

          {/* ── SIGNUP step 1 ── */}
          {mode === 'signup' && step === 1 && (
            <form className="account-form" onSubmit={handleSendPin} noValidate>
              <div className="account-field-row">
                <div className="field">
                  <label className="field__label">First name</label>
                  <input className="field__input" placeholder="Jane"
                    value={regForm.firstName} onChange={e => setRegForm({ ...regForm, firstName: e.target.value })} required />
                </div>
                <div className="field">
                  <label className="field__label">Last name</label>
                  <input className="field__input" placeholder="Doe"
                    value={regForm.lastName} onChange={e => setRegForm({ ...regForm, lastName: e.target.value })} required />
                </div>
              </div>
              <div className="field">
                <label className="field__label">Email</label>
                <input className="field__input" type="email" placeholder="you@example.com"
                  value={regForm.email} onChange={e => setRegForm({ ...regForm, email: e.target.value })} required />
              </div>
              <button className="btn-primary account-submit" type="submit" disabled={loading}>
                {loading ? 'Sending…' : 'Send Verification PIN'}
              </button>
              {msg.text && <p className={msg.type === 'success' ? 'api-success' : 'api-error'}>{msg.text}</p>}
              <button type="button" className="account-text-btn" onClick={() => switchMode('login')}>← Back to Log In</button>
            </form>
          )}

          {/* ── SIGNUP step 2: PIN boxes ── */}
          {mode === 'signup' && step === 2 && (
            <form className="account-form" onSubmit={handleVerifyPin} noValidate>
              <p className="account-hint">We sent a PIN to <strong>{regForm.email}</strong></p>
              <div className="field" style={{ alignItems: 'center' }}>
                <label className="field__label" style={{ textAlign: 'center', marginBottom: '14px' }}>Verification PIN</label>
                <PinInput
                  value={regForm.pin}
                  onChange={val => { setRegForm(f => ({ ...f, pin: val })); clearMsg(); }}
                  hasError={pinHasError}
                />
              </div>
              <button className="btn-primary account-submit" type="submit" disabled={loading || regForm.pin.length < 6}>
                {loading ? 'Verifying…' : 'Verify PIN'}
              </button>
              {msg.text && <p className={msg.type === 'success' ? 'api-success' : 'api-error'}>{msg.text}</p>}
              <div style={{ textAlign: 'center', marginTop: '.25rem' }}>
                <button type="button" className="account-text-btn"
                  onClick={handleResendPin} disabled={loading || countdown > 0}>
                  {countdown > 0 ? `Resend in ${countdown}s` : 'Resend PIN'}
                </button>
              </div>
            </form>
          )}

          {/* ── SIGNUP step 3: password ── */}
          {mode === 'signup' && step === 3 && (
            <form className="account-form" onSubmit={handleCreateAccount} noValidate>
              <div className="field">
                <label className="field__label">Choose a password</label>
                <input className="field__input" type="password" placeholder="Min. 8 characters"
                  value={regForm.password} onChange={e => setRegForm({ ...regForm, password: e.target.value })} required />
              </div>
              <button className="btn-primary account-submit" type="submit" disabled={loading}>
                {loading ? 'Creating…' : 'Create Account'}
              </button>
              {msg.text && <p className={msg.type === 'success' ? 'api-success' : 'api-error'}>{msg.text}</p>}
            </form>
          )}

          {/* ── FORGOT step 1 ── */}
          {mode === 'forgot' && step === 1 && (
            <form className="account-form" onSubmit={handleForgotPin} noValidate>
              <div className="field">
                <label className="field__label">Email address</label>
                <input className="field__input" type="email" placeholder="you@example.com"
                  value={forgotEmail} onChange={e => setForgotEmail(e.target.value)} required />
              </div>
              <button className="btn-primary account-submit" type="submit" disabled={loading}>
                {loading ? 'Sending…' : 'Send Recovery PIN'}
              </button>
              {msg.text && <p className={msg.type === 'success' ? 'api-success' : 'api-error'}>{msg.text}</p>}
              <button type="button" className="account-text-btn" onClick={() => switchMode('login')}>← Back to Log In</button>
            </form>
          )}

          {/* ── FORGOT step 2: PIN + new password ── */}
          {mode === 'forgot' && step === 2 && (
            <form className="account-form" onSubmit={handleResetPassword} noValidate>
              <p className="account-hint">We sent a recovery PIN to <strong>{forgotEmail}</strong></p>
              <div className="field" style={{ alignItems: 'center' }}>
                <label className="field__label" style={{ textAlign: 'center', marginBottom: '14px' }}>Recovery PIN</label>
                <PinInput
                  value={forgotPin}
                  onChange={val => { setForgotPin(val); clearMsg(); }}
                  hasError={msg.type === 'error'}
                />
              </div>
              <div className="field">
                <label className="field__label">New password</label>
                <input className="field__input" type="password" placeholder="Min. 8 characters"
                  value={newPassword} onChange={e => setNewPassword(e.target.value)} required />
              </div>
              <button className="btn-primary account-submit" type="submit" disabled={loading || forgotPin.length < 6}>
                {loading ? 'Resetting…' : 'Reset Password'}
              </button>
              {msg.text && <p className={msg.type === 'success' ? 'api-success' : 'api-error'}>{msg.text}</p>}
              <div style={{ textAlign: 'center', marginTop: '.25rem' }}>
                <button type="button" className="account-text-btn"
                  onClick={handleResendForgotPin} disabled={loading || countdown > 0}>
                  {countdown > 0 ? `Resend in ${countdown}s` : 'Resend PIN'}
                </button>
              </div>
            </form>
          )}

        </div>
      </div>
      <Footer />
    </>
  );
}
